function mostrarCategorias(genero) {
  const menu = document.querySelector(".menu");
  menu.innerHTML = `
    <button onclick="mostrarMenuPrincipal()">← Volver</button>
    <h3>Categorías para ${genero === 'mujer' ? 'Mujer' : 'Hombre'}</h3>
  `;

  categorias[genero].forEach(cat => {
    const btn = document.createElement("button");
    btn.textContent = cat;
    btn.onclick = () => mostrarProductos(genero, cat);
    menu.appendChild(btn);
  });

  // Añadir la sección de contacto al final
  const contactoDiv = document.createElement("div");
  contactoDiv.className = "contacto";
  contactoDiv.innerHTML = `
    <h3>Contáctanos</h3>
    <p>Celular: <a href="https://wa.me/qr/3SY7N2JCX3OVE1" target="_blank" rel="noopener noreferrer">314 282 0164</a></p>
    <p>Facebook: <a href="https://www.facebook.com/share/1BCmiTfnSu/" target="_blank" rel="noopener noreferrer">Ver perfil</a></p>
    <p>Instagram: <a href="https://www.instagram.com/eileendayanna_10?igsh=dzM4bmZ3d29pZ3J0" target="_blank" rel="noopener noreferrer">Ver perfil</a></p>
  `;
  menu.appendChild(contactoDiv);

  // Limpiar contenido central
  document.getElementById("contenido").innerHTML = `
    <h2>Selecciona una categoría para ver nuestros productos.</h2>
  `;
}

function mostrarMenuPrincipal() {
  const menu = document.querySelector(".menu");
  menu.innerHTML = `
    <button onclick="mostrarCategorias('mujer')">Para Mujeres</button>
    <button onclick="mostrarCategorias('hombre')">Para Hombres</button>
    <div class="contacto">
      <h3>Contáctanos</h3>
      <p>Celular: <a href="https://wa.me/qr/3SY7N2JCX3OVE1" target="_blank" rel="noopener noreferrer">314 282 0164</a></p>
      <p>Facebook: <a href="https://www.facebook.com/share/1BCmiTfnSu/" target="_blank" rel="noopener noreferrer">Ver perfil</a></p>
      <p>Instagram: <a href="https://www.instagram.com/eileendayanna_10?igsh=dzM4bmZ3d29pZ3J0" target="_blank" rel="noopener noreferrer">Ver perfil</a></p>
    </div>
  `;

  document.getElementById("contenido").innerHTML = `
    <h2>Bienvenid@ a La Boutique de Eileen</h2>
    <p>Selecciona una categoría para ver nuestros productos.</p>
  `;
}

function mostrarProductos(genero, categoria) {
  const contenedor = document.getElementById("contenido");
  contenedor.innerHTML = `<h2>${categoria} para ${genero === 'mujer' ? 'Mujer' : 'Hombre'}</h2>`;

  productosPorCategoria[genero][categoria].forEach(producto => {
    const div = document.createElement("div");
    div.className = "producto";
    div.innerHTML = `
      <img src="${producto.imagen}" alt="${producto.nombre}" />
      <h3>${producto.nombre} - $${producto.precio.toLocaleString()}</h3>
      <button onclick="añadirAlCarrito('${producto.nombre}', ${producto.precio})">Añadir al carrito</button>
    `;
    contenedor.appendChild(div);
  });
}

function añadirAlCarrito(nombre, precio) {
  carrito.push({ nombre, precio });
  actualizarCarrito();
}

function actualizarCarrito() {
  document.getElementById("contador").textContent = carrito.length;
  localStorage.setItem("carrito", JSON.stringify(carrito));
}

function mostrarCarrito() {
  const contenedor = document.getElementById("contenido");
  contenedor.innerHTML = "<h2>🛒 Tu carrito de compras</h2>";

  if (carrito.length === 0) {
    contenedor.innerHTML += "<p>Tu carrito está vacío.</p>";
    return;
  }

  carrito.forEach((item, index) => {
    const div = document.createElement("div");
    div.className = "producto";
    div.innerHTML = `
      <h3>${item.nombre}</h3>
      <p>Precio: $${item.precio.toLocaleString()}</p>
      <button onclick="eliminarDelCarrito(${index})">❌ Eliminar</button>
    `;
    contenedor.appendChild(div);
  });

  const total = carrito.reduce((sum, item) => sum + item.precio, 0);
  contenedor.innerHTML += `<h3>Total: $${total.toLocaleString()}</h3>`;

  // ✅ Aquí están los botones que deben verse
  contenedor.innerHTML += `
    <button onclick="vaciarCarrito()" style="margin-right: 10px; background-color: #ff6b6b; color: white; padding: 10px; border: none; border-radius: 5px; cursor: pointer;">
      🧹 Vaciar carrito
    </button>
    <button onclick="finalizarCompra()" style="background-color: #6a994e; color: white; padding: 10px; border: none; border-radius: 5px; cursor: pointer;">
      🛍️ Finalizar compra
    </button>
  `;
}
function finalizarCompra() {
  if (carrito.length === 0) {
    alert("Tu carrito está vacío.");
    return;
  }

  mostrarFactura(); // ✅ Aquí se llama la factura
}

function mostrarFactura() {
  const contenedor = document.getElementById("contenido");
  const fecha = new Date().toLocaleString();

  let facturaHTML = `
    <div class="factura">
      <h2>🧾 Factura de compra</h2>
      <p><strong>Fecha:</strong> ${fecha}</p>
      <table>
        <thead>
          <tr>
            <th>📋 Producto</th>
            <th>💲 Precio</th>
          </tr>
        </thead>
        <tbody>
  `;

  carrito.forEach((item) => {
    facturaHTML += `
      <tr>
        <td>${item.nombre}</td>
        <td>$${item.precio.toLocaleString()}</td>
      </tr>
    `;
  });

  const total = carrito.reduce((sum, item) => sum + item.precio, 0);

  facturaHTML += `
        </tbody>
      </table>
      <h3>Total a pagar: $${total.toLocaleString()}</h3>
      <p>🎉 ¡Gracias por tu compra en <strong>La Boutique de Eileen</strong>! 💖</p>
      <div class="botones">
        <button onclick="window.print()">🖨️ Imprimir factura</button>
        <button onclick="volverAlInicio()">🔙 Volver al inicio</button>
      </div>
    </div>
  `;

  contenedor.innerHTML = facturaHTML;
  carrito = [];
  actualizarCarrito();
}
function volverAlInicio() {
  const contenedor = document.getElementById("contenido");
  contenedor.innerHTML = `
    <h2>Bienvenid@ a La Boutique de Eileen</h2>
    <p>Selecciona una categoría para ver nuestros productos.</p>
  `;
}
function eliminarDelCarrito(index) {
  carrito.splice(index, 1); // Elimina 1 elemento desde el índice
  actualizarCarrito();      // Actualiza el contador y localStorage
  mostrarCarrito();         // Vuelve a dibujar el carrito actualizado
}


